struct common_chat_template {
    jinja::program prog;              // Parsed Jinja template program
    std::string bos_tok;              // Beginning of sequence token
    std::string eos_tok;              // End of sequence token
    std::string src;                  // Original template source string
    chat_template_caps caps;          // Template capabilities

    // Constructor: parses the template source
    common_chat_template(const std::string & src, 
                        const std::string & bos_token, 
                        const std::string & eos_token) {
        jinja::lexer lexer;
        auto lexer_res = lexer.tokenize(src);
        this->prog = jinja::parse_from_tokens(lexer_res);
        this->src = lexer_res.source;
        this->bos_tok = bos_token;
        this->eos_tok = eos_token;
        this->caps = jinja::caps_get(prog);
    }

    const std::string & source() const { return src; }
    const std::string & bos_token() const { return bos_tok; }
    const std::string & eos_token() const { return eos_tok; }
    chat_template_caps original_caps() const { return caps; }
};
```

