static void foreach_function(const json & tools, 
                            const std::function<void(const json &)> & fn) {
    for (const auto & tool : tools) {
        // Skip non-function tools
        if (!tool.contains("type") || tool.at("type") != "function" || 
            !tool.contains("function")) {
            LOG_INF("Skipping tool without function: %s", tool.dump(2).c_str());
            continue;
        }
        fn(tool);
    }
}
